	// 扩展区间时加入元素
	void add(const vector<int>& pre, int pos) {
		current_ans += mp[pre[pos]];
		mp[pre[pos]]++;
	}

	// 缩小区间时删除元素
	void del(const vector<int>& pre, int pos) {
