		current_ans -= mp[pre[pos]];
	}

void solve(int CASE)
{
	int n, k, q; cin >> n >> k >> q;
	string s; cin >> s; s = ' ' + s;

	// 对【前缀字符串 26 个字母各个拿了多少的状态】进行哈希
	var char_hash = vector<ull>(26);
	fa(i, 0, 25)char_hash[i] = MT::randint<ull>(1, 1e18);
	var sum = vector<int>(26);
	var pre = vector<ull>(n + 1);
	var b = vector<ull>();
	b.pb(pre[0]);
	fa(i, 1, n) {
		sum[s[i] - 'a'] = (sum[s[i] - 'a'] + 1) % k;
		fa(j, 0, 25)pre[i] += sum[j] * char_hash[j];
		b.pb(pre[i]);
	}

	// 对哈希值进行离散化
	sort(all(b));
	b.erase(unique(all(b)), b.end());
	var find = [&](ull value)->int {
		return upper_bound(all(b), value) - b.begin();
		};
	var hash = vector<int>(n + 1);
	fa(i, 0, n)hash[i] = find(pre[i]);

	var mo = Mo(n, q);
	mo.init();
	fa(i, 1, q) {
		int l, r; cin >> l >> r;
		// 注意，按照公式，我们一定要找 [l - 1, r] 区间里是否有相等的
		mo.update_query(l - 1, r, i);
	}
	mo.sort_query();

	fa(i, 1, q) {
		const var& [l, r, id] = mo.queries[i];
		mo.update_lr(hash, l, r, id);
	}
	fa(i, 1, q)cout << mo.ans[i] << endl;
 	return;
}
